#!/usr/bin/env node
/**
 * One-shot bootstrap for RAG eval environment.
 *
 * 1. Reads VITE_CONVEX_URL from apps/web/.env.local
 * 2. Generates a secure RAG_EVAL_SECRET
 * 3. Appends both to repo-root .env (local-only vars)
 * 4. Pushes RAG_EVALS_ENABLED=true and RAG_EVAL_SECRET to the dev Convex deployment
 * 5. Strips RAG eval vars from .env.local so they do not override repo-root .env
 *
 * Usage:
 *   bun run eval:rag:bootstrap-env
 *
 * Does NOT upload RAG_EVAL_CONVEX_URL to Convex (that is CLI-only).
 */

const fs = require("fs");
const path = require("path");
const { execSync } = require("child_process");

const WEB_ENV_PATH = path.join("apps", "web", ".env.local");
const REPO_ENV_PATH = path.join(process.cwd(), ".env");
const REPO_ENV_LOCAL_PATH = path.join(process.cwd(), ".env.local");

/** Same rules as convex-env-utils shouldSkipPullKey — keep in sync. */
function isRagEvalLocalKey(key) {
  return key === "RAG_EVALS_ENABLED" || key.startsWith("RAG_EVAL_");
}

function stripRagEvalKeysFromEnvFile(filePath) {
  if (!fs.existsSync(filePath)) return false;
  const lines = fs.readFileSync(filePath, "utf-8").split(/\r?\n/);
  const kept = [];
  let removed = 0;
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) {
      kept.push(line);
      continue;
    }
    const eq = trimmed.indexOf("=");
    if (eq <= 0) {
      kept.push(line);
      continue;
    }
    const key = trimmed.slice(0, eq).trim();
    if (isRagEvalLocalKey(key)) {
      removed++;
      continue;
    }
    kept.push(line);
  }
  if (removed === 0) return false;
  let merged = kept.join("\n");
  if (!merged.endsWith("\n")) merged += "\n";
  fs.writeFileSync(filePath, merged, "utf-8");
  return true;
}

function readViteConvexUrl() {
  if (!fs.existsSync(WEB_ENV_PATH)) {
    console.error(`FATAL: ${WEB_ENV_PATH} not found.`);
    console.error(
      "  Run the web dev server once (bun run dev:web) to generate it, or create it manually with VITE_CONVEX_URL."
    );
    process.exit(1);
  }

  const content = fs.readFileSync(WEB_ENV_PATH, "utf-8");
  const match = content.match(/^VITE_CONVEX_URL=(.+)$/m);
  if (!match) {
    console.error(`FATAL: VITE_CONVEX_URL not found in ${WEB_ENV_PATH}`);
    process.exit(1);
  }
  return match[1].trim();
}

function generateSecret() {
  return require("crypto").randomBytes(24).toString("hex");
}

function appendToRepoEnv(convexUrl, secret) {
  const lines = [];

  if (fs.existsSync(REPO_ENV_PATH)) {
    const existing = fs.readFileSync(REPO_ENV_PATH, "utf-8");
    if (existing.includes("RAG_EVAL_CONVEX_URL=")) {
      console.log(`RAG_EVAL_CONVEX_URL already exists in ${REPO_ENV_PATH}. Skipping append.`);
      return false;
    }
    lines.push("");
  }

  lines.push("# ─── RAG Eval (auto-generated by bootstrap-rag-eval-env.js) ───");
  lines.push(`RAG_EVAL_CONVEX_URL=${convexUrl}`);
  lines.push(`RAG_EVAL_SECRET=${secret}`);
  lines.push("");

  fs.appendFileSync(REPO_ENV_PATH, lines.join("\n"));
  console.log(`Appended RAG eval vars to ${REPO_ENV_PATH}`);
  return true;
}

function setConvexEnv(key, value) {
  const cmd = `npx convex env set ${key}=${value}`;
  console.log(`  → ${cmd}`);
  try {
    execSync(cmd, { stdio: "inherit" });
  } catch (_err) {
    console.error(`\nFATAL: Failed to set Convex env var ${key}.`);
    console.error(
      "  Ensure you are logged in to Convex (npx convex dev) and this is the correct dev deployment."
    );
    process.exit(1);
  }
}

function main() {
  console.log("=== RAG Eval Environment Bootstrap ===\n");

  const convexUrl = readViteConvexUrl();
  console.log(`Found VITE_CONVEX_URL: ${convexUrl}`);

  const secret = generateSecret();
  console.log(`Generated RAG_EVAL_SECRET: ${secret.slice(0, 8)}... (${secret.length} chars)\n`);

  const appended = appendToRepoEnv(convexUrl, secret);

  console.log("\nPushing eval gate variables to Convex dev deployment...");
  setConvexEnv("RAG_EVALS_ENABLED", "true");
  setConvexEnv("RAG_EVAL_SECRET", secret);

  if (stripRagEvalKeysFromEnvFile(REPO_ENV_LOCAL_PATH)) {
    console.log(
      `\nRemoved RAG eval vars from ${REPO_ENV_LOCAL_PATH} (eval CLI reads repo-root .env only).`
    );
  }

  console.log("\n=== Bootstrap complete ===");
  console.log("Next steps:");
  console.log("  1. Verify:  bun run eval:rag:dry");
  console.log("  2. Run one: bun run eval:rag -- --case agentic-patterns-20");

  if (!appended) {
    console.log("\nNOTE: RAG_EVAL_CONVEX_URL was already present in .env.");
    console.log("      If you need to rotate the secret, delete the old lines and re-run.");
  }
}

main();
